// TUTOR MODE — Universal Concept Library
// ============================================================================
// One pre-written explainer per artifact type. These do NOT vary by stock or
// scenario — they teach the universal concept. The applied (specific) layer
// is generated by /api/tutor at request time.
// ============================================================================

export interface TutorConcept {
  artifact: ArtifactType
  title: string
  /** ~3 short paragraphs explaining the universal concept */
  paragraphs: string[]
  /** Glossary terms — render as dotted-underlined words in the body text */
  glossary: { term: string; def: string }[]
}

